package org.apache.commons.codec.binary.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.codec.binary.Base64InputStream;

import java.io.*;

import static org.junit.Assert.*;

// Emits three line-feeds '\n' in a row, one at a time, and then EOF.
// Recreates the bug described in CODEC-105.
class Codec105ErrorInputStream extends InputStream {
    private static final int EOF = -1;
    int countdown = 3;

    public int read() throws IOException {
        if (this.countdown-- > 0) {
            return '\n';
        } else {
            return EOF;
        }
    }

    public int read(byte b[], int pos, int len) throws IOException {
        if (this.countdown-- > 0) {
            b[pos] = '\n';
            return 1;
        } else {
            return EOF;
        }
    }
}

public class StepDefs {

    private Base64InputStream base64InputStream;
    private InputStream underlyingStream;
    private int[] readResults;

    @Given("^a Base64InputStream is configured to encode data$")
    public void a_Base64InputStream_is_configured_to_encode_data() {
        // Use the same error-prone stream as the original test that fails
        underlyingStream = new Codec105ErrorInputStream();

        // Create a Base64InputStream configured to encode (true parameter means encoding)
        base64InputStream = new Base64InputStream(underlyingStream, true, 0, null); // true for encode mode
    }

    @Given("^the underlying input stream returns 3 bytes of data \\(e\\.g\\.\\, three newline characters\\)$")
    public void the_underlying_input_stream_returns_3_bytes_of_data_e_g_three_newline_characters() {
        // Already handled in the previous step
    }

    @Given("^the Base64InputStream reads from the underlying stream using a 1-byte buffer, forcing the internal buffer to be reset to 1 byte$")
    public void the_Base64InputStream_reads_from_the_underlying_stream_using_a_1_byte_buffer_forcing_the_internal_buffer_to_be_reset_to_1_byte() {
        // The setup is already done in the first step, but we're ensuring the conditions that trigger the bug
        // The issue occurs when internal buffer gets resized incorrectly
    }

    @When("^I read from the Base64InputStream 5 times$")
    public void i_read_from_the_Base64InputStream_5_times() throws IOException {
        readResults = new int[5];

        // Reading one byte at a time to trigger the internal buffer reset issue
        for (int i = 0; i < 5; i++) {
            readResults[i] = base64InputStream.read();
        }
    }

    @Then("^the first 4 reads should return the expected Base64 characters \\(e\\.g\\.\\, 'C', 'g', 'o', 'K'\\)$")
    public void the_first_4_reads_should_return_the_expected_Base64_characters_e_g_C_g_o_K() {
        // Three newlines (0x0A, 0x0A, 0x0A) should encode to "CgoK" in Base64
        assertEquals((int)'C', readResults[0]);
        assertEquals((int)'g', readResults[1]);
        assertEquals((int)'o', readResults[2]);
        assertEquals((int)'K', readResults[3]);
    }

    @Then("^the 5th read should return -1 indicating EOF$")
    public void the_5th_read_should_return_minus1_indicating_EOF() {
        assertEquals(-1, readResults[4]);
    }

    @Then("^the process should not fail with an ArrayIndexOutOfBoundsException due to insufficient buffer resizing$")
    public void the_process_should_not_fail_with_an_ArrayIndexOutOfBoundsException_due_to_insufficient_buffer_resizing() {
        // If we reach this step without an exception, the test passes for this requirement
        // This scenario specifically tests that the bug doesn't occur
        assertTrue(true); // Just a placeholder assertion
    }

    // Cleanup method to close streams
    public void cleanup() {
        try {
            if (base64InputStream != null) {
                base64InputStream.close();
            }
            if (underlyingStream != null) {
                underlyingStream.close();
            }
        } catch (IOException e) {
            // Ignore errors during cleanup
        }
    }
}

